VALUES
  ('police-3218f787-moex-00087', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '憲法本文有關憲法基本權利之規定 ，下列何者之規定內容最為具體？', '["憲法第14條之集會、結社自由", "憲法第11條之言論、講學、著作及出版自由", "憲法第8條之人身自由", "憲法第7條之平等權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00088', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '下列有關訴訟權之敘述，何者錯誤？', '["憲法保障人民訴訟權，係指人民於其權利或法律上利益遭受侵害時，有請求法院救濟之權利", "此乃基於有權利即有救濟之憲法原理", "訴訟權之具體內容，應由立法機關制定法院組織與訴訟程序有關之法律，始得實現", "立法機關得因身分之不同，而予以限制，不受憲法第23條之拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00089', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋意旨，關於國家賠償之憲法保障內涵，下列敘述何者錯誤？', '["如果沒有法律規定，人民尚不得依照憲法第24條，直接行使國家賠償請求權", "就公務員怠於執行職務之國家賠償責任，不以人民應先請求公務員執行而怠於執行為必要", "就公務員執行職務之國家賠償責任，立法者對於是否採無過失責任享有立法形成自由", "法律規範目的如有保障人民生命、身體及財產等法益之意旨時，即可直接認定被害人得向 國家請求損害賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00090', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '受國民教育以外教育之權利，係下列何憲法條文之保障範圍？', '["第21條受國民教育之權利", "第22條之其他自由或權利", "第159條國民受教育之機會平等", "第163條國家應注重各地區教育之均衡發展"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00091', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '關於基本權利之第三人效力，下列敘述何者正確？', '["意指國家不得干預人民間的契約自由，以保障私法自治", "意指基本權利拘束行政、立法、司法各部門", "意指透過解釋私法上的一般條款與不確定法律概念，使基本權利得直接適用於私人關係", "有直接適用、間接適用和無拘束力等不同見解"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00092', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '某國營事業的工廠排放工業廢氣及廢水，導致居民因惡性腫瘤的死亡率明顯高於全國平均值 。下列敘述何者正確？', '["基本權不僅拘束國家公權力行為，也拘束行政私法行為", "國營事業的工廠排放廢水及廢氣，屬於公權力行為", "國營事業並非政府，故人民無法主張生存權受到侵害", "健康權非我國憲法所明文保障，故人民無法主張健康權受到侵害"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00093', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院釋字第688號解釋，立法者於制定法律時，創設一具有體系規範意義之法律原則時 ，除有基於重大公益之考量外，應受其原則拘束以維持法律體系之一貫性，是為體系之正義 。其後立法有違背此體系正義時，係違反下列何原則？', '["比例原則", "平等原則", "信賴保護原則", "誠信原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00094', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋，公務人員依法銓敘取得之官等俸級，非經公務員懲戒機關依法定程序 之審議決定，不得降級或減俸，係對何種權利之保障？', '["參政權", "應考試權", "訴訟權", "服公職權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00095', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '下列何者屬於自然人能夠享有，法人不能享有的權利？', '["居住遷徙自由", "工作之自由", "參政權", "集會結社自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00096', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '關於總統、副總統之缺位或不能視事，下列敘述何者錯誤？', '["總統缺位時，由副總統繼任，至總統任期屆滿為止", "副總統缺位時，總統應於3個月內提名候選人，由立法院補選，繼任至原任期屆滿為止", "總統、副總統均缺位時，由行政院院長代行其職權，至原任期屆滿為止", "總統、副總統均不能視事時，由行政院院長代行其職權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
